using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class PayrollTraining : TrainingContentBase
{
    public PayrollTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll Overview",
            Slug = "payroll-overview",
            Summary = "What payroll features are available in QB Engineer: employee self-service, pay stubs, tax documents, and admin upload workflows.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","pay-stubs","tax-documents"]""",
            ContentJson = """{"body":"## Payroll Overview\n\nQB Engineer provides employee self-service payroll features so every team member can view their earnings, deductions, and year-end tax documents without bothering HR or management. Admins and Office Managers can upload documents on behalf of employees, and if a QuickBooks Payroll integration is connected, records sync automatically.\n\n### What's Included\n\nThe payroll module lives under **Account** in the sidebar and has two pages:\n\n- **Pay Stubs** — A chronological list of every pay period showing pay date, period range, gross pay, deductions, and net pay. Each stub can have a PDF attachment for download.\n- **Tax Documents** — Year-end tax forms (W-2, W-2c, 1099-MISC, 1099-NEC, and Other) organized by tax year with PDF downloads.\n\n### Employee Self-Service\n\nEvery employee can access their own records at any time:\n\n1. Navigate to **Account → Pay Stubs** to see all pay stubs sorted by most recent pay date first.\n2. Navigate to **Account → Tax Documents** to see all tax documents sorted by tax year.\n3. Click the download icon on any row that has a PDF attachment to view or save the document.\n\nEmployees can only see their own records — they cannot view pay information for other users.\n\n### Admin Upload\n\nAdmins and Office Managers can upload payroll documents for any employee:\n\n- **Pay Stub Upload** — Provide pay period start/end dates, pay date, gross pay, net pay, and an optional PDF file attachment. The system calculates total deductions as the difference between gross and net pay.\n- **Tax Document Upload** — Select the document type (W-2, W-2c, 1099-MISC, 1099-NEC, or Other), specify the tax year, and attach the PDF.\n\nManually uploaded documents show a gray 'Manual' chip in the Source column. Documents synced from an accounting provider show a blue 'Synced' chip.\n\n### How Payroll Connects to Other Features\n\n**Accounting Integration:** When QuickBooks Payroll (or another provider) is connected, pay stubs and tax documents sync automatically. Synced records are read-only and show the 'Synced' source badge.\n\n**Employee Profile:** Pay stubs are tied to each user's account. Admins can view and manage payroll records from the employee administration panel.\n\n**File Storage:** PDF attachments for pay stubs and tax documents are stored in MinIO (the same secure file storage used across the platform). Downloads are served directly from the API.\n\n### Pay Stub Deductions\n\nEach pay stub can include itemized deductions across 15 categories:\n\n- **Taxes:** Federal Tax, State Tax, Social Security, Medicare\n- **Insurance:** Health Insurance, Dental, Vision, Life Insurance, Disability Insurance\n- **Savings:** 401(k) Retirement, HSA, FSA\n- **Other:** Union Dues, Garnishment/Child Support, Other\n\nDeductions are visible in the pay stub detail and sum to the Total Deductions amount shown in the table.\n\n### When to Use Payroll Features\n\n- When you need to check your latest pay stub or verify a deduction\n- When downloading a W-2 or 1099 for tax filing season\n- When an admin needs to manually upload a corrected pay stub (W-2c)\n- When onboarding a new accounting integration and verifying synced records match","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll — Guided Tour",
            Slug = "payroll-walkthrough",
            Summary = "A guided tour of the Account > Pay Stubs page: table layout, columns, downloading PDFs, and navigating to tax documents.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","walkthrough"]""",
            ContentJson = """{"appRoute":"/account/pay-stubs","startButtonLabel":"Tour Payroll","steps":[{"element":".account-sidebar","popover":{"title":"Account Sidebar","description":"The Account sidebar lists all self-service pages. Pay Stubs and Tax Documents are under the Payroll section. Click either link to switch between them.","side":"right"}},{"element":".pay-stubs__title","popover":{"title":"Pay Stubs Page","description":"This page shows all your pay stubs in reverse chronological order (most recent first). Each row represents one pay period with key financial totals.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Pay Stubs Table","description":"The table displays columns for Pay Date, Period (start-end range), Gross Pay, Net Pay, Deductions, Source, and a download action. Click column headers to sort. All currency values are right-aligned for easy scanning.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll Field Reference",
            Slug = "payroll-field-reference",
            Summary = "Complete reference for every field, column, button, status, and validation rule in the Pay Stubs and Tax Documents pages.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/account/pay-stubs"]""",
            Tags = """["payroll","account","reference"]""",
            ContentJson = """{"title":"Payroll Field Reference","groups":[{"heading":"Pay Stubs — Table Columns","items":[{"label":"Pay Date","value":"Date column (MM/dd/yyyy), sortable. The date the payment was issued. Default sort: descending (newest first)."},{"label":"Period","value":"Text column showing pay period range: start date – end date (MM/dd/yyyy – MM/dd/yyyy). Not sortable."},{"label":"Gross Pay","value":"Currency column, sortable, right-aligned. Total earnings before deductions and taxes."},{"label":"Net Pay","value":"Currency column, sortable, right-aligned. Take-home pay after all deductions."},{"label":"Deductions","value":"Currency column, sortable, right-aligned. Sum of all deductions (Gross Pay minus Net Pay)."},{"label":"Source","value":"Sortable. Displays a chip: blue 'Synced' for accounting-provider imports, gray 'Manual' for admin-uploaded records."},{"label":"Actions","value":"Download icon button. Visible only when the pay stub has a PDF file attachment. Opens PDF in a new browser tab."}]},{"heading":"Pay Stub Entity Fields","items":[{"label":"Pay Period Start (required)","value":"Date. The first day of the pay period covered by this stub. Sent as ISO UTC string."},{"label":"Pay Period End (required)","value":"Date. The last day of the pay period. Must be on or after Pay Period Start."},{"label":"Pay Date (required)","value":"Date. The date the payment was issued to the employee."},{"label":"Gross Pay (required)","value":"Decimal currency amount. Total earnings before deductions. Must be greater than zero."},{"label":"Net Pay (required)","value":"Decimal currency amount. Take-home pay after deductions. Must be greater than zero and less than or equal to Gross Pay."},{"label":"Total Deductions","value":"Computed: Gross Pay minus Net Pay. Automatically calculated on the server."},{"label":"Total Taxes","value":"Decimal. Sum of tax-category deductions (Federal Tax + State Tax + Social Security + Medicare). Set to 0 for manual uploads."},{"label":"File Attachment","value":"Optional PDF file. Uploaded via the file storage system and linked by FileAttachmentId."},{"label":"Source","value":"Enum: Accounting (synced from provider) or Manual (admin-uploaded). Set automatically based on upload method."},{"label":"External ID","value":"Optional string. The provider's unique identifier for synced records. Null for manual uploads."}]},{"heading":"Pay Stub Deduction Fields","items":[{"label":"Category (required)","value":"Enum. One of 15 categories: FederalTax, StateTax, SocialSecurity, Medicare, HealthInsurance, Retirement401k, Dental, Vision, HSA, FSA, LifeInsurance, DisabilityInsurance, UnionDues, GarnishmentChildSupport, Other."},{"label":"Description","value":"Text. Human-readable label for the deduction (e.g., 'Federal Income Tax', 'Medical PPO Plan', '401k Match')."},{"label":"Amount","value":"Decimal currency amount. The dollar value deducted for this line item."}]},{"heading":"Pay Stub Deduction Categories","items":[{"label":"FederalTax","value":"Federal income tax withholding based on W-4 elections."},{"label":"StateTax","value":"State income tax withholding based on state withholding form and work location."},{"label":"SocialSecurity","value":"Employee's share of Social Security tax (FICA, 6.2% up to wage base)."},{"label":"Medicare","value":"Employee's share of Medicare tax (1.45%, plus 0.9% additional above threshold)."},{"label":"HealthInsurance","value":"Employee's premium contribution for medical/health insurance."},{"label":"Retirement401k","value":"Employee's 401(k) retirement plan contribution (pre-tax or Roth)."},{"label":"Dental","value":"Employee's dental insurance premium."},{"label":"Vision","value":"Employee's vision insurance premium."},{"label":"HSA","value":"Health Savings Account contribution (pre-tax)."},{"label":"FSA","value":"Flexible Spending Account contribution (pre-tax)."},{"label":"LifeInsurance","value":"Employee-paid life insurance premium (above employer-provided amount)."},{"label":"DisabilityInsurance","value":"Short-term or long-term disability insurance premium."},{"label":"UnionDues","value":"Union membership dues deducted per collective bargaining agreement."},{"label":"GarnishmentChildSupport","value":"Court-ordered garnishments, child support, or wage assignments."},{"label":"Other","value":"Any deduction that does not fit the above categories."}]},{"heading":"Tax Documents — Table Columns","items":[{"label":"Tax Year","value":"Numeric column, sortable. The calendar year the tax document covers (e.g., 2025). Width: 100px."},{"label":"Document Type","value":"Sortable. Displays the human-readable label: W-2, W-2c (Corrected), 1099-MISC, 1099-NEC, or Other. Width: 160px."},{"label":"Employer","value":"Sortable. The employer name on the document. Shows '—' (em dash) when not set."},{"label":"Source","value":"Sortable. Chip: blue 'Synced' or gray 'Manual'. Same behavior as pay stubs."},{"label":"Actions","value":"Download icon button. Visible only when a PDF file is attached."}]},{"heading":"Tax Document Entity Fields","items":[{"label":"Document Type (required)","value":"Enum: W2 (standard wage/tax statement), W2c (corrected W-2), Misc1099 (miscellaneous income), Nec1099 (nonemployee compensation), Other."},{"label":"Tax Year (required)","value":"Integer. The calendar year the document applies to (e.g., 2025). Must be a valid 4-digit year."},{"label":"Employer Name","value":"Optional text. The employer name shown on the document. May be null for manually uploaded documents."},{"label":"File Attachment","value":"Optional PDF file. The actual tax form document, linked by FileAttachmentId."},{"label":"Source","value":"Enum: Accounting or Manual. Same as pay stubs."},{"label":"External ID","value":"Optional string. Provider's unique ID for synced documents."}]},{"heading":"Tax Document Types","items":[{"label":"W-2","value":"Wage and Tax Statement. Standard year-end form showing total wages, tips, and taxes withheld by the employer. Issued to all W-2 employees."},{"label":"W-2c","value":"Corrected Wage and Tax Statement. Issued when the original W-2 contained errors (wrong SSN, incorrect amounts, etc.)."},{"label":"1099-MISC","value":"Miscellaneous Income. Reports payments like rents, royalties, prizes, awards, and other non-employee income over $600."},{"label":"1099-NEC","value":"Nonemployee Compensation. Reports payments of $600 or more to independent contractors and freelancers."},{"label":"Other","value":"Any tax document that does not fit the standard types above (e.g., state-specific forms, 1095 health coverage forms)."}]},{"heading":"Buttons and Actions","items":[{"label":"Download PDF (icon button)","value":"Opens the pay stub or tax document PDF in a new browser tab. Only visible when a FileAttachmentId exists on the record. Tooltip: 'Download Pay Stub PDF' or 'Download Tax Document PDF'."},{"label":"Admin: Upload Pay Stub","value":"Admin/Office Manager action. Opens a form to enter pay period dates, pay date, gross pay, net pay, and attach a PDF for a specific employee."},{"label":"Admin: Upload Tax Document","value":"Admin/Office Manager action. Opens a form to select document type, tax year, and attach a PDF for a specific employee."},{"label":"Admin: Delete Pay Stub","value":"Admin/Office Manager action. Soft-deletes a manually uploaded pay stub. Synced records cannot be deleted."},{"label":"Admin: Delete Tax Document","value":"Admin/Office Manager action. Soft-deletes a manually uploaded tax document. Synced records cannot be deleted."},{"label":"Admin: Sync Payroll","value":"Triggers a manual sync with the connected accounting/payroll provider. Only available when an integration is configured."}]},{"heading":"Validation Rules","items":[{"label":"Pay Period Start","value":"Required. Must be a valid date."},{"label":"Pay Period End","value":"Required. Must be a valid date on or after Pay Period Start."},{"label":"Pay Date","value":"Required. Must be a valid date."},{"label":"Gross Pay","value":"Required. Must be a positive number."},{"label":"Net Pay","value":"Required. Must be a positive number and less than or equal to Gross Pay."},{"label":"Tax Year","value":"Required. Must be a valid 4-digit year."},{"label":"Document Type","value":"Required. Must be one of the five valid types (W2, W2c, Misc1099, Nec1099, Other)."}]},{"heading":"Access Control","items":[{"label":"Employee (self-service)","value":"Can view and download their own pay stubs and tax documents only. No create, edit, or delete access."},{"label":"Admin / Office Manager","value":"Can view, upload, and delete payroll records for any employee. Can trigger payroll sync."},{"label":"All other roles","value":"Same as Employee — self-service view of their own records only."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payroll Knowledge Check",
            Slug = "payroll-quiz",
            Summary = "Test your knowledge of QB Engineer's payroll features: pay stubs, tax documents, deductions, and admin workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["payroll","account","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pr1","text":"Where do you find your pay stubs in QB Engineer?","options":[{"id":"a","text":"Admin → Payroll → Pay Stubs"},{"id":"b","text":"Account → Pay Stubs in the sidebar","isCorrect":true},{"id":"c","text":"Dashboard → Payroll widget → View All"},{"id":"d","text":"Reports → Payroll → My Pay Stubs"}],"explanation":"Pay stubs are a self-service feature under Account → Pay Stubs. Every employee can access their own records from the Account sidebar."},{"id":"pr2","text":"A pay stub shows Gross Pay of $3,200 and Net Pay of $2,450. What is the Total Deductions amount?","options":[{"id":"a","text":"$2,450"},{"id":"b","text":"$750","isCorrect":true},{"id":"c","text":"$3,200"},{"id":"d","text":"$5,650"}],"explanation":"Total Deductions = Gross Pay − Net Pay = $3,200 − $2,450 = $750. The system calculates this automatically."},{"id":"pr3","text":"You see a blue 'Synced' chip in the Source column of a pay stub. What does this mean?","options":[{"id":"a","text":"The pay stub was manually uploaded by an admin and verified"},{"id":"b","text":"The pay stub was automatically imported from the connected accounting/payroll provider","isCorrect":true},{"id":"c","text":"The pay stub PDF has been downloaded and cached locally"},{"id":"d","text":"The pay stub has been synced to your personal tax software"}],"explanation":"A blue 'Synced' chip indicates the record was automatically imported from the connected accounting provider (e.g., QuickBooks Payroll). Gray 'Manual' chips indicate admin-uploaded records."},{"id":"pr4","text":"Which of the following is NOT a valid pay stub deduction category in QB Engineer?","options":[{"id":"a","text":"HealthInsurance"},{"id":"b","text":"Retirement401k"},{"id":"c","text":"ParkingBenefit","isCorrect":true},{"id":"d","text":"GarnishmentChildSupport"}],"explanation":"QB Engineer supports 15 deduction categories: FederalTax, StateTax, SocialSecurity, Medicare, HealthInsurance, Retirement401k, Dental, Vision, HSA, FSA, LifeInsurance, DisabilityInsurance, UnionDues, GarnishmentChildSupport, and Other. ParkingBenefit is not one of them — it would fall under 'Other'."},{"id":"pr5","text":"An employee needs their W-2 for tax filing. Where do they find it?","options":[{"id":"a","text":"Account → Tax Documents, filtered by the relevant tax year","isCorrect":true},{"id":"b","text":"Account → Pay Stubs → Annual Summary tab"},{"id":"c","text":"Admin → Reports → Tax Forms"},{"id":"d","text":"Account → Compliance Forms → Tax Documents"}],"explanation":"Tax documents (W-2, 1099, etc.) are accessed at Account → Tax Documents. The table shows Tax Year, Document Type, Employer, and Source columns. The employee clicks the download icon to get the PDF."},{"id":"pr6","text":"What is the difference between a W-2 and a W-2c?","options":[{"id":"a","text":"W-2 is for full-time employees, W-2c is for contractors"},{"id":"b","text":"W-2 is the standard wage/tax statement, W-2c is a corrected version issued when the original had errors","isCorrect":true},{"id":"c","text":"W-2 covers federal taxes, W-2c covers state taxes"},{"id":"d","text":"W-2 is issued quarterly, W-2c is the annual summary"}],"explanation":"A W-2c (Corrected Wage and Tax Statement) is issued when the original W-2 contained errors — such as a wrong SSN, incorrect wage amounts, or wrong tax withholding figures."},{"id":"pr7","text":"An admin needs to upload a pay stub for an employee. Which fields are required?","options":[{"id":"a","text":"Pay Date, Gross Pay, and a PDF attachment"},{"id":"b","text":"Pay Period Start, Pay Period End, Pay Date, Gross Pay, and Net Pay","isCorrect":true},{"id":"c","text":"Employee name, Pay Date, Net Pay, and deduction breakdown"},{"id":"d","text":"Pay Date, Gross Pay, Net Pay, Federal Tax, and State Tax amounts"}],"explanation":"The required fields for uploading a pay stub are: Pay Period Start, Pay Period End, Pay Date, Gross Pay, and Net Pay. The PDF attachment is optional, and Total Deductions is calculated automatically as the difference between Gross Pay and Net Pay."},{"id":"pr8","text":"Can an employee delete their own pay stubs or tax documents?","options":[{"id":"a","text":"Yes, they can delete any of their own records"},{"id":"b","text":"Yes, but only manually uploaded ones"},{"id":"c","text":"No — only Admins and Office Managers can delete payroll records","isCorrect":true},{"id":"d","text":"Yes, but only after the tax year has closed"}],"explanation":"Employees have view-only access to their own payroll records. Only Admins and Office Managers can upload or delete payroll documents, and synced records from an accounting provider cannot be deleted at all."},{"id":"pr9","text":"What type of tax document would you expect to see for an independent contractor?","options":[{"id":"a","text":"W-2"},{"id":"b","text":"W-2c"},{"id":"c","text":"1099-NEC","isCorrect":true},{"id":"d","text":"1099-MISC"}],"explanation":"Independent contractors receive a 1099-NEC (Nonemployee Compensation) for payments of $600 or more. The 1099-MISC is used for other types of miscellaneous income like rents and royalties, not for contractor compensation."},{"id":"pr10","text":"A pay stub's download icon is missing from the Actions column. What does this mean?","options":[{"id":"a","text":"The pay stub has been archived and is no longer accessible"},{"id":"b","text":"The pay stub does not have a PDF file attachment","isCorrect":true},{"id":"c","text":"You don't have permission to download this particular stub"},{"id":"d","text":"The file server is offline and downloads are temporarily unavailable"}],"explanation":"The download icon only appears when the pay stub has an associated PDF file attachment (FileAttachmentId is not null). Some synced records may not include a PDF depending on the provider, and manual uploads may have been created without attaching a file."}]}"""
        });

        Log.Information("Seeded Payroll training modules");
    }
}
